import{_ as e,c as o,o as a,ae as r}from"./chunks/framework.Ck3L_38O.js";const h=JSON.parse('{"title":"06 - Column-Store Databases","description":"","frontmatter":{},"headers":[],"relativePath":"course/CMU_15-445_Fall2025/lec6.md","filePath":"course/CMU_15-445_Fall2025/lec6.md"}'),n={name:"course/CMU_15-445_Fall2025/lec6.md"};function d(s,t,l,i,c,g){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="_06-column-store-databases" tabindex="-1">06 - Column-Store Databases <a class="header-anchor" href="#_06-column-store-databases" aria-label="Permalink to &quot;06 - Column-Store Databases&quot;">​</a></h1><h2 id="database-workload" tabindex="-1">Database Workload <a class="header-anchor" href="#database-workload" aria-label="Permalink to &quot;Database Workload&quot;">​</a></h2><p>目前市面上有常见的三种数据库</p><h3 id="on-line-transaction-processing-oltp" tabindex="-1">On-Line Transaction Processing (OLTP) <a class="header-anchor" href="#on-line-transaction-processing-oltp" aria-label="Permalink to &quot;On-Line Transaction Processing (OLTP)&quot;">​</a></h3><p><strong>联机事务处理</strong><br> 特点：高并发、低延迟、每次操作数据量小、事务性强（ACID）。<br> 典型场景：用户注册、下单、发评论、转账等。<br> 性能要求：快速响应，支持大量并发写入。<br> 技术重点：行式存储（row-oriented）、索引优化、事务日志、锁机制。</p><p>Tuple 有几个字段时，查询某一个字段时，不管其他的字段是否需要，都会被读取加载到内存中，即使它们是没有用处的数据，这也就是 OLTP 不适合用于分析的原因。<br> 事实上，除非批量导出，否则分析时几乎不会出现 <code>SELECT *</code> 。</p><h3 id="on-line-analytical-processing-olap" tabindex="-1">On-Line Analytical Processing (OLAP) <a class="header-anchor" href="#on-line-analytical-processing-olap" aria-label="Permalink to &quot;On-Line Analytical Processing (OLAP)&quot;">​</a></h3><p><strong>联机分析处理</strong><br> 特点：读多写少、查询复杂、涉及大量数据扫描和聚合。<br> 典型场景：商业智能（BI）、报表、用户行为分析。<br> 性能要求：高效处理大规模数据聚合，支持复杂查询。<br> 技术重点：列式存储（column-oriented）、数据压缩、向量化执行、MPP 架构。</p><p>对于 OLAP 来说，虽然 read 很快，但是相对的 write 就慢，每次 write 都需要将表按字段分离，再进行写入。<br> 同时， OLAP 做<strong>点查(point queries)</strong> 很慢，因为需要从多个列查询结果，然后进行拼接。</p><h3 id="hybrid-transaction-analytical-processing" tabindex="-1">Hybrid Transaction + Analytical Processing <a class="header-anchor" href="#hybrid-transaction-analytical-processing" aria-label="Permalink to &quot;Hybrid Transaction + Analytical Processing&quot;">​</a></h3><p><strong>混合事务/分析处理</strong> 目标：在同一个系统中同时高效支持 OLTP 和 OLAP。<br> 问题：由于需要兼容两种需求，因此两种需求都不能做得很好，导致市场的选择会出现问题。<br> 代表系统：SingleStore、TiDB、Oracle In-Memory、SQL Server Hekaton。</p><hr><p>相对来说<br> OLTP 大多数操作是<strong>写入操作</strong>，各种操作也很简单。(实际读取更多，相对 OLAP 写入更多)<br> OLAP 大多数操作是<strong>读取操作</strong>，且查询非常复杂。(实际几乎不写入，只会定期批量导入)<br> HTAP 处于 OLTP 和 OLAP 的中间。</p><p>一些特殊的情况，例如在 PostgreSQL 中，它虽然是 OLTP ，但是如果存储了大文本数据，它会单独设置一个 Page ，而不会将数据存到 Slot 中。</p><h2 id="decomposition-storage-model-dsm" tabindex="-1">Decomposition Storage Model (DSM) <a class="header-anchor" href="#decomposition-storage-model-dsm" aria-label="Permalink to &quot;Decomposition Storage Model (DSM)&quot;">​</a></h2><p>OLAP 的 Tuple 有两种存储方式</p><h3 id="fixed-length-offsets" tabindex="-1">Fixed-length Offsets <a class="header-anchor" href="#fixed-length-offsets" aria-label="Permalink to &quot;Fixed-length Offsets&quot;">​</a></h3><p>所有列按相同行序存储，第 i 个元素天然对齐一个 Tuple<br> 要求每个字段大小固定</p><p>可能有额外的存储开销</p><h4 id="database-compression" tabindex="-1">Database compression <a class="header-anchor" href="#database-compression" aria-label="Permalink to &quot;Database compression&quot;">​</a></h4><p>目标：</p><ul><li>生成固定长度的值</li><li>推迟解压数据的时间(不解压就能够知道里面包含了什么)</li><li>压缩是无损的</li></ul><p>实现方法：</p><ul><li>Block-level (按 Page 压缩)</li><li>Tuple-level (按 Tuple 压缩)</li><li>Attribute-level (对单个属性压缩)</li><li>Colunm-level (对列压缩)</li></ul><p>对于 MySQL(InnoDB) 来说，它使用的 Block-level 压缩，对 Page 进行压缩存储。</p><blockquote><p>在每个数据页的页头（header） 中，有一个叫 “mod log”（修改日志） 的区域。它类似于预写日志（WAL），用于记录对这个页所做的修改，但这些修改尚未应用到压缩数据本身。</p><p>当我需要访问一个 Page 时， buffer pool 会像往常一样从磁盘读取它，以压缩的形式读入内存中， 如果需要 Write ，直接定位到它然后覆盖即可，不需要解压，在 mod log 中写一条记录，对这个 Tuple 的这个字段，用新值覆盖，当 mod log 写满时，我才需要解压整个页，应用所有修改，然后清空 mod log；<br> 如果需要 Read ，如果刚刚被 Write 过，直接读取 mod log 进行了，但如果需要查看 Tuple 内部的实际值，就必须解压整个页，然后合并 mod log。</p><p>这是一种常见模式：系统会有一个快速写入区（delta store / mod log）</p><p>当 mod log 满了需要同步的时候，会产生阻塞</p></blockquote><p>对于 OLAP 来说，更常见的是 Colunm-level ，因为一个列里有许多属性，它们都是重复，可以增加压缩的效率。</p><h5 id="encoding" tabindex="-1">Encoding <a class="header-anchor" href="#encoding" aria-label="Permalink to &quot;Encoding&quot;">​</a></h5><table tabindex="0"><thead><tr><th>压缩技术 (Compression Scheme)</th><th>适用场景</th><th>核心原理</th><th>优点</th><th>缺点 / 挑战</th><th>典型系统 / 备注</th></tr></thead><tbody><tr><td><strong>行程编码 (RLE, Run-Length Encoding)</strong></td><td>列中存在大量<strong>连续重复值</strong>（如布尔标志、状态字段）</td><td>将连续相同值编码为 <code>(值, 起始偏移, 重复次数)</code> 三元组</td><td>极高压缩比（当重复值集中时）；支持直接在压缩域聚合（如 COUNT）</td><td>需<strong>数据排序</strong>才能高效；无序数据压缩后反而更大</td><td>ORC、Parquet；常与 Delta 编码组合使用</td></tr><tr><td><strong>位打包 (Bit Packing)</strong></td><td>数值远小于其数据类型上限（如 <code>age</code> 用 32 位 int 存 0–127）</td><td>仅存储有效低位，丢弃高位无意义的 0</td><td>显著节省空间（如 32 位 → 8 位）；保持固定长度，利于向量化</td><td>插入超大值需<strong>补丁表（Patch Table）</strong>；增加读取逻辑复杂度</td><td>Amazon Redshift（MOSTLY8 编码）</td></tr><tr><td><strong>位图编码 (Bitmap Encoding)</strong></td><td><strong>低基数（Low-Cardinality）</strong> 分类列（如 <code>gender</code>, <code>is_active</code>）</td><td>为每个唯一值维护一个位图，第 i 位 = 1 表示第 i 行是该值</td><td>查询极快（位运算如 AND/OR/POPCNT）；压缩率高（1 行 = 1 位）</td><td>高基数列（如 user_id）会导致<strong>空间爆炸</strong></td><td>ClickHouse、Doris；高基数时需 Roaring Bitmaps</td></tr><tr><td><strong>Delta 编码 (Delta Encoding)</strong></td><td><strong>平缓变化的有序数值</strong>（如时间戳、自增 ID、温度）</td><td>存储与前一个值（或基准值）的<strong>差值（delta）</strong>，而非绝对值</td><td>差值通常很小，可用更少位表示；适合进一步压缩（如 RLE）</td><td>要求数据<strong>有序</strong>；随机访问需从头累加</td><td>Parquet、ORC；常用于时间序列数据</td></tr><tr><td><strong>字典编码 (Dictionary Encoding)</strong></td><td><strong>重复字符串或枚举值</strong>（如 <code>country</code>, <code>product_name</code>）</td><td>将唯一值映射为<strong>固定长度整数 ID</strong>，列中存 ID，另存字典（值 ↔ ID）</td><td>高压缩率；整数比较快；支持<strong>顺序保留（order-preserving）</strong> 范围查询</td><td>唯一值过多时字典变大；插入新值可能需重建</td><td><strong>最常用</strong>；ORC、Parquet、ClickHouse、Doris</td></tr></tbody></table><blockquote><p><strong>关键设计原则</strong>：</p><ul><li><strong>组合使用</strong>：多种压缩技术可叠加（如 Dictionary + RLE、Delta + RLE），效果是<strong>乘法级</strong>的。</li><li><strong>顺序保留</strong>：字典按值排序，使压缩数据仍能高效支持 <code>WHERE name &gt; &#39;Alice&#39;</code> 等范围查询。</li><li><strong>OLAP 友好</strong>：依赖“数据不可变 + 批量写入”假设，避免频繁更新压缩结构。</li></ul></blockquote><h3 id="embedded-tuple-ids" tabindex="-1">Embedded Tuple Ids <a class="header-anchor" href="#embedded-tuple-ids" aria-label="Permalink to &quot;Embedded Tuple Ids&quot;">​</a></h3><p>每列独立存储 + 附加 Tuple ID + 外部索引对齐</p><p>不能使用</p>',33)])])}const b=e(n,[["render",d]]);export{h as __pageData,b as default};
